mapper.select:
SELECT * FROM audit_plan
        AND plan_type=#{planType}
        AND plan_year=#{planYear}
        AND status=#{status}
        ORDER BY plan_year DESC, create_time DESC

SELECT * FROM audit_unit
        AND unit_type=#{unitType}
        ORDER BY create_time DESC

SELECT l.*, u.unit_name FROM audit_leader l LEFT JOIN audit_unit u ON u.id=l.unit_id
AND l.unit_id=#{unitId}
ORDER BY l.create_time DESC
